import{_ as e,o as t,c as p,a0 as r}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"할로우 나이트 실크송","description":"","frontmatter":{},"headers":[],"relativePath":"outta-space/knowledge/games/할로우-나이트-실크송.md","filePath":"outta-space/knowledge/games/할로우-나이트-실크송.md"}'),o={name:"outta-space/knowledge/games/할로우-나이트-실크송.md"};function _(n,a,l,i,s,d){return t(),p("div",null,[...a[0]||(a[0]=[r('<h1 id="할로우-나이트-실크송" tabindex="-1">할로우 나이트 실크송 <a class="header-anchor" href="#할로우-나이트-실크송" aria-label="Permalink to &quot;할로우 나이트 실크송&quot;">​</a></h1><h2 id="_1-핵심-플레이-경험" tabindex="-1">1. 핵심 플레이 경험 <a class="header-anchor" href="#_1-핵심-플레이-경험" aria-label="Permalink to &quot;1. 핵심 플레이 경험&quot;">​</a></h2><p>약 20시간 플레이한 후기다.</p><p>술술 대못강화 한 번 얻고 선율 하나 더 얻으면 노멀 엔딩을 볼 수 있을 것 같아 후기를 남긴다. 전작은 112퍼센트 클리어에 3문까지 깬 사람 기준으로, 이 게임은 장점과 단점이 모두 미친 수준으로 강하다.</p><p>전체적으로 사람을 굉장히 피곤하게 만드는 요소가 많다. 전작의 불편했던 요소들, 예를 들어 나침반, 지도 구매, 워프 부족 같은 문제를 조금이라도 개선했을 줄 알았지만, 오히려 여러 면에서 더 피곤해진 느낌이 있다.</p><h2 id="_2-조작감과-시스템" tabindex="-1">2. 조작감과 시스템 <a class="header-anchor" href="#_2-조작감과-시스템" aria-label="Permalink to &quot;2. 조작감과 시스템&quot;">​</a></h2><p>호넷의 액션성 자체는 좋다. 기사가 대시 후 달리기도 없고 공격도 빠르지 않았던 것에 비해, 호넷은 더 빠르고 역동적이다. 할나보다는 격겜 캐릭터를 조작하는 느낌이고, 스프라이트나 히트박스 처리도 취해놓은 듯한 빠른 전투감이 있다.</p><p>하지만 시스템적으로는 불편함이 많다.</p><p>회복은 1힐에서 딸깍 3힐로 바뀌었고 공중에서도 가능하다. 편리하지만 실크를 채워야 한다는 제약이 있다. 9번 공격해야 회복할 수 있는 구조라 흐름이 독특하다. 순간적으로 회복이 터지는 방식은 좋지만, 공격받으면 멈추는 기존 방식이 더 나았을 수도 있다.</p><p>부적 시스템은 악상 시스템으로 바뀌었고, 도구, 수비, 유틸 종류별로 슬롯이 나뉘었다. 그러나 조합하는 맛이 사라졌고, 성능도 애매해져서 감흥이 적었다. 사실상 몇 개만 고정으로 쓰게 되는 느낌이었다.</p><p>문장 시스템은 전작 유저를 배려하다가 나온 이상한 시스템처럼 느껴졌다. 공격 방향과 이동 방식까지 바꾸는 구조인데, 익숙해지기 전까지는 방랑자 문장을 다시 끼고 다니게 된다.</p><h2 id="_3-전투와-보스전" tabindex="-1">3. 전투와 보스전 <a class="header-anchor" href="#_3-전투와-보스전" aria-label="Permalink to &quot;3. 전투와 보스전&quot;">​</a></h2><p>전투는 재미있지만, 불쾌한 요소가 많다.</p><p>2딜을 주는 잡몹이 너무 많고, 잡몹과 함정이 겹치면서 최악의 시너지를 낸다. 체력도 전작보다 체감상 많고 수도 많으며, 회복 자원도 별도로 필요하다. 작은 날벌레나 가시 표창 같은 적은 조작 피로감을 크게 만든다.</p><p>투기장식 전투도 많다. 위에서 말한 양심 없는 잡몹들이 두세 마리씩 계속 나오기 때문에, 좁은 지형에서는 주변 의자를 찾는 습관이 생길 정도였다.</p><p>보스전은 대체로 좋다. 특히 보스를 잡아도 무조건 안 죽고, 뒤에 능력이나 부적이라도 있을 줄 알았더니 그냥 통행권을 주는 식의 배치가 있었지만, 보스 패턴 자체는 재미있다.</p><p>다만 패링 기능을 따로 넣지 않은 것이 아쉽다. 공격이 패링을 겸하는 구조라 타이밍이 매우 빡세고, 연타로 들어오는 공격이 많은 만큼 별도의 패링 시스템이 있었다면 더 재미있었을 것 같다.</p><h2 id="_4-그래픽-사운드-연출" tabindex="-1">4. 그래픽, 사운드, 연출 <a class="header-anchor" href="#_4-그래픽-사운드-연출" aria-label="Permalink to &quot;4. 그래픽, 사운드, 연출&quot;">​</a></h2><p>그래픽과 사운드는 여전히 좋다.</p><p>새로운 지역을 탐험하는 재미, 시각적 분위기, 음악은 강점이다. 그러나 맵 디자인과 길찾기는 피로하다. 맵 디자인은 보상이 없는 곳도 많고, 길을 뚫는 방식이 불친절하다. 위퍼 같이 사람을 피곤하게 만드는 요소도 있다.</p><p>의자와 저장장치 문제도 불편했다. 의자를 열기 위해 돈을 쓰거나, 상점에서 의미 없는 아이템을 사야 하는 흐름은 피로감을 만든다. 돈도 많이 모이긴 하지만 그만큼 잃는 속도도 빨라 스트레스가 있다.</p><h2 id="_5-몰입도와-재플레이-가치" tabindex="-1">5. 몰입도와 재플레이 가치 <a class="header-anchor" href="#_5-몰입도와-재플레이-가치" aria-label="Permalink to &quot;5. 몰입도와 재플레이 가치&quot;">​</a></h2><p>실크송은 분명 재미있는 게임이다. 액션성이 좋아졌고, 호넷을 조작하는 맛도 있다. 그러나 난이도와 피로감이 과하게 높다.</p><p>이 게임은 나를 즐겁게 만들면서도 동시에 지치게 한다. 불편한 요소를 더 어렵게 만드는 방식으로 설계된 부분이 많아, 쉽게 추천하기는 어렵다.</p><p>한 줄 평: 액션성과 보스전은 강력하지만, 맵 탐색과 시스템 피로도가 지나치게 높은 후속작.</p>',25)])])}const u=e(o,[["render",_]]);export{c as __pageData,u as default};
